public class StringCreation {
 public static void main(String[] args) {
 String str1 = "Hello"; // literal
 String str2 = new String("Hello"); // new keyword
 System.out.println(str1);
 System.out.println(str2);
 }
}

public class StringMethods {
 public static void main(String[] args) {
 String str = "Hello World";
 System.out.println(str.length()); // length
 System.out.println(str.charAt(0)); // charAt
 System.out.println(str.substring(0, 5)); // substring
 System.out.println(str.indexOf("World")); // indexOf
 System.out.println(str.replace("World", "Java")); // replace
 }
}

public class StringComparison {
 public static void main(String[] args) {
 String str1 = "Hello";
 String str2 = "Hello";
 String str3 = new String("Hello");
 System.out.println(str1.equals(str2)); // equals()
 System.out.println(str1 == str2); // ==
 System.out.println(str1.equals(str3)); // equals()
 System.out.println(str1 == str3); // ==
 }
}
